import React from 'react';

const WorkerProfileCards = ({ workers }) => {
  if (!workers || workers.length === 0) {
    return (
      <div className="card">
        <h3 className="card-title">👥 Worker Profiles</h3>
        <div className="alert alert-info">
          ℹ️ No workers onboarded yet. Start by registering workers to see their profiles.
        </div>
      </div>
    );
  }

  const getRiskLevelColor = (score) => {
    if (score <= 30) return 'risk-low';
    if (score <= 60) return 'risk-medium';
    return 'risk-high';
  };

  const getRiskLevelText = (score) => {
    if (score <= 30) return 'LOW';
    if (score <= 60) return 'MEDIUM';
    return 'HIGH';
  };

  const getPlatformIcon = (platform) => {
    switch (platform.toLowerCase()) {
      case 'swiggy': return '🟡';
      case 'zomato': return '🔴';
      case 'uber_eats': return '⚫';
      default: return '🚚';
    }
  };

  return (
    <div className="card">
      <h3 className="card-title">👥 Worker Profiles</h3>
      <p className="card-subtitle">
        Active gig workers with AI-calculated risk profiles and coverage details
      </p>

      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', 
        gap: '1.5rem',
        marginTop: '1.5rem'
      }}>
        {workers.map((worker) => (
          <div 
            key={worker.id} 
            className="worker-profile-card"
            style={{
              background: 'rgba(255, 255, 255, 0.95)',
              backdropFilter: 'blur(10px)',
              borderRadius: '16px',
              padding: '1.5rem',
              boxShadow: '0 4px 20px rgba(0, 0, 0, 0.08)',
              border: '1px solid rgba(255, 255, 255, 0.2)',
              transition: 'all 0.3s ease'
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-4px)';
              e.currentTarget.style.boxShadow = '0 8px 30px rgba(0, 0, 0, 0.12)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = '0 4px 20px rgba(0, 0, 0, 0.08)';
            }}
          >
            {/* Worker Header */}
            <div style={{ 
              display: 'flex', 
              justifyContent: 'space-between', 
              alignItems: 'flex-start',
              marginBottom: '1rem'
            }}>
              <div>
                <h4 style={{ 
                  margin: '0 0 0.25rem 0', 
                  color: '#2d3748',
                  fontSize: '1.1rem',
                  fontWeight: '600'
                }}>
                  {worker.name}
                </h4>
                <div style={{ 
                  display: 'flex', 
                  alignItems: 'center', 
                  gap: '0.5rem',
                  color: '#718096',
                  fontSize: '0.9rem'
                }}>
                  <span>{getPlatformIcon(worker.platform)}</span>
                  <span>{worker.platform}</span>
                  <span>•</span>
                  <span>📍 {worker.city}</span>
                </div>
              </div>
              <span className={`risk-badge ${getRiskLevelColor(worker.riskScore)}`}>
                {getRiskLevelText(worker.riskScore)}
              </span>
            </div>

            {/* Worker Stats */}
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(2, 1fr)', 
              gap: '1rem',
              marginBottom: '1rem'
            }}>
              <div style={{ 
                background: '#f7fafc', 
                padding: '0.75rem', 
                borderRadius: '8px',
                textAlign: 'center'
              }}>
                <div style={{ 
                  fontSize: '1.25rem', 
                  fontWeight: 'bold', 
                  color: '#4a5568' 
                }}>
                  ₹{worker.weeklyPremium}
                </div>
                <div style={{ 
                  fontSize: '0.8rem', 
                  color: '#718096',
                  marginTop: '0.25rem'
                }}>
                  Weekly Premium
                </div>
              </div>
              <div style={{ 
                background: '#f7fafc', 
                padding: '0.75rem', 
                borderRadius: '8px',
                textAlign: 'center'
              }}>
                <div style={{ 
                  fontSize: '1.25rem', 
                  fontWeight: 'bold', 
                  color: '#4a5568' 
                }}>
                  {worker.riskScore}
                </div>
                <div style={{ 
                  fontSize: '0.8rem', 
                  color: '#718096',
                  marginTop: '0.25rem'
                }}>
                  Risk Score
                </div>
              </div>
            </div>

            {/* Additional Details */}
            <div style={{ 
              fontSize: '0.85rem', 
              color: '#718096',
              marginBottom: '1rem'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                <span>Average Daily Earnings:</span>
                <strong style={{ color: '#4a5568' }}>₹{worker.averageDailyEarnings || 0}</strong>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                <span>Working Hours:</span>
                <strong style={{ color: '#4a5568' }}>{worker.workingHours || 0}h/day</strong>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span>Claims History:</span>
                <strong style={{ color: '#4a5568' }}>
                  {worker.claimHistory ? worker.claimHistory.length : 0} claims
                </strong>
              </div>
            </div>

            {/* Risk Indicators */}
            <div style={{ 
              display: 'flex', 
              gap: '0.5rem', 
              flexWrap: 'wrap',
              marginTop: 'auto'
            }}>
              {worker.floodRiskZone && (
                <span style={{
                  background: 'linear-gradient(135deg, #4299e1, #3182ce)',
                  color: 'white',
                  padding: '0.25rem 0.5rem',
                  borderRadius: '12px',
                  fontSize: '0.75rem',
                  fontWeight: '500'
                }}>
                  🌊 Flood Zone
                </span>
              )}
              {worker.pollutionRiskZone && (
                <span style={{
                  background: 'linear-gradient(135deg, #9f7aea, #805ad5)',
                  color: 'white',
                  padding: '0.25rem 0.5rem',
                  borderRadius: '12px',
                  fontSize: '0.75rem',
                  fontWeight: '500'
                }}>
                  💨 Pollution Zone
                </span>
              )}
              {worker.claimHistory && worker.claimHistory.length > 0 && (
                <span style={{
                  background: 'linear-gradient(135deg, #48bb78, #38a169)',
                  color: 'white',
                  padding: '0.25rem 0.5rem',
                  borderRadius: '12px',
                  fontSize: '0.75rem',
                  fontWeight: '500'
                }}>
                  ✅ Active Coverage
                </span>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Summary Stats */}
      <div style={{ 
        marginTop: '2rem', 
        padding: '1rem',
        background: '#f7fafc',
        borderRadius: '12px',
        display: 'flex',
        justifyContent: 'space-around',
        flexWrap: 'wrap',
        gap: '1rem'
      }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#4a5568' }}>
            {workers.length}
          </div>
          <div style={{ fontSize: '0.9rem', color: '#718096' }}>Total Workers</div>
        </div>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#48bb78' }}>
            {workers.filter(w => w.riskScore <= 30).length}
          </div>
          <div style={{ fontSize: '0.9rem', color: '#718096' }}>Low Risk</div>
        </div>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#ed8936' }}>
            {workers.filter(w => w.riskScore > 30 && w.riskScore <= 60).length}
          </div>
          <div style={{ fontSize: '0.9rem', color: '#718096' }}>Medium Risk</div>
        </div>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#f56565' }}>
            {workers.filter(w => w.riskScore > 60).length}
          </div>
          <div style={{ fontSize: '0.9rem', color: '#718096' }}>High Risk</div>
        </div>
      </div>
    </div>
  );
};

export default WorkerProfileCards;
